replacements.new:
const contentBox = new Box(0, 1, (content) => theme.bg("userMessageBg", content));
const message = new Markdown(this.text, 0, 0, this.markdownTheme, {
    color: (content) => theme.fg("userMessageText", content),
}, { preserveOrderedListMarkers: true, preserveBackslashEscapes: true });
contentBox.addChild({
    render(width) {
        const prefix = theme.fg("userMessageText", " > "), childWidth = Math.max(1, width - 3);
        const lines = [...message.render(childWidth)];
        if (lines.length == 0) return [truncateToWidth(prefix, width)];
        lines[0] = truncateToWidth(prefix + lines[0], width);
        for (let i = 1; i < lines.length; i++) lines[i] = truncateToWidth("   " + lines[i], width);
        return lines;
    },
    invalidate() {
        message.invalidate();
    },
});

